#include "median_filter.h"
#include <Arduino.h>
#define MAX_W 32
static float _buf[MAX_W],_sorted[MAX_W];
static uint8_t _w=5,_idx=0,_cnt=0;
void median_setup(uint8_t w){_w=min(w,(uint8_t)MAX_W);_idx=0;_cnt=0;}
float median_add(float v){_buf[_idx]=v;_idx=(_idx+1)%_w;if(_cnt<_w)_cnt++;memcpy(_sorted,_buf,sizeof(float)*_cnt);for(int i=0;i<_cnt-1;i++)for(int j=i+1;j<_cnt;j++)if(_sorted[j]<_sorted[i]){float t=_sorted[i];_sorted[i]=_sorted[j];_sorted[j]=t;}return _sorted[_cnt/2];}
float median_get(){return _sorted[_cnt/2];}
